/* ─── STORAGE HELPERS ─────────────────────────────────────────────────── */
function loadData() {
  try {
    const p = localStorage.getItem("ah_projects");
    const i = localStorage.getItem("ah_info");
    return {
      projects: p ? JSON.parse(p) : DEFAULT_PROJECTS,
      info: i ? JSON.parse(i) : DEFAULT_INFO,
    };
  } catch { return { projects: DEFAULT_PROJECTS, info: DEFAULT_INFO }; }
}
function saveProjects(p) { try { localStorage.setItem("ah_projects", JSON.stringify(p)); } catch {} }
function saveInfo(i) { try { localStorage.setItem("ah_info", JSON.stringify(i)); } catch {} }

/* ─── NAV ────────────────────────────────────────────────────────────── */
function Nav({ active, onAdmin }) {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);

  const links = ["About","Projects","Skills","Contact"];

  const handleLink = (href) => {
    setOpen(false);
    document.querySelector(href)?.scrollIntoView({ behavior:"smooth" });
  };

  return (
    <>
      {open && <div onClick={() => setOpen(false)} style={{ position:"fixed", inset:0, zIndex:1099, background:"rgba(0,0,0,0.65)" }} />}
      <nav style={{ position:"fixed", top:0, left:0, right:0, zIndex:1100, padding:"0 20px", height:66, display:"flex", alignItems:"center", justifyContent:"space-between", background:scrolled||open?"rgba(8,8,16,0.97)":"transparent", backdropFilter:scrolled?"blur(20px)":"none", borderBottom:scrolled?"1px solid rgba(255,255,255,0.06)":"none", transition:"all 0.4s" }}>
        <a href="#hero" style={{ display:"flex", alignItems:"center", gap:10 }}>
          <div style={{ width:36, height:36, borderRadius:10, background:"linear-gradient(135deg,#FF4D6D,#A78BFA)", display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"Syne", fontWeight:800, fontSize:14, color:"#fff", flexShrink:0 }}>AH</div>
          <span className="nav-name" style={{ fontFamily:"Syne", fontWeight:700, fontSize:16, color:"#fff", letterSpacing:"0.04em" }}>ALI HASSAN</span>
        </a>

        {/* Desktop links */}
        <div className="nav-links-desktop" style={{ display:"flex", alignItems:"center", gap:32 }}>
          {links.map(l => (
            <button key={l} onClick={() => handleLink(`#${l.toLowerCase()}`)} className={`nav-link ${active===l.toLowerCase()?"active":""}`} style={{ background:"none", border:"none" }}>{l}</button>
          ))}
          <button onClick={onAdmin} style={{ background:"none", border:"1px solid rgba(255,255,255,0.15)", color:"rgba(255,255,255,0.5)", padding:"7px 14px", borderRadius:7, fontFamily:"DM Sans", fontSize:12, cursor:"pointer", transition:"all 0.2s" }}>Admin ⚙️</button>
          <a href="#contact" className="btn-primary nav-cta" style={{ padding:"9px 20px", fontSize:13, animation:"none", boxShadow:"none" }}>Let's Talk</a>
        </div>

        {/* Mobile hamburger */}
        <div className="hamburger" onClick={() => setOpen(!open)}>
          <span style={{ transform:open?"rotate(45deg) translate(5px,5px)":"none" }} />
          <span style={{ opacity:open?0:1 }} />
          <span style={{ transform:open?"rotate(-45deg) translate(5px,-5px)":"none" }} />
        </div>
      </nav>

      {/* Mobile menu */}
      {open && (
        <div className="nav-links open">
          {links.map(l => (
            <button key={l} onClick={() => handleLink(`#${l.toLowerCase()}`)} className={`nav-link ${active===l.toLowerCase()?"active":""}`} style={{ background:"none", border:"none", textAlign:"left" }}>{l}</button>
          ))}
          <button onClick={() => { setOpen(false); onAdmin(); }} style={{ background:"none", border:"1px solid rgba(255,255,255,0.15)", color:"rgba(255,255,255,0.5)", padding:"10px 14px", borderRadius:7, fontFamily:"DM Sans", fontSize:15, cursor:"pointer", textAlign:"left" }}>Admin ⚙️</button>
          <a href="#contact" onClick={() => setOpen(false)} className="btn-primary" style={{ padding:"12px 20px", fontSize:15, animation:"none", boxShadow:"none", marginTop:8 }}>Let's Talk</a>
        </div>
      )}
    </>
  );
}

/* ─── HERO ───────────────────────────────────────────────────────────── */
