/* ─── ADMIN PANEL ─────────────────────────────────────────────────────── */
function AdminPanel({ onClose, projects, setProjects, info, setInfo }) {
  const [tab, setTab] = useState("info");
  const [pass, setPass] = useState("");
  const [authed, setAuthed] = useState(false);
  const [editProj, setEditProj] = useState(null);
  const [newProj, setNewProj] = useState({ title:"", cat:"Web", year:"2025", desc:"", color:"#4DFFB4", icon:"🌐", link:"" });
  const [infoEdit, setInfoEdit] = useState({ ...info });
  const [saved, setSaved] = useState(false);

  if (!authed) return (
    <div style={{ position:"fixed", inset:0, zIndex:2000, background:"rgba(0,0,0,0.85)", backdropFilter:"blur(10px)", display:"flex", alignItems:"center", justifyContent:"center", padding:24 }}>
      <div style={{ background:"#0f0f1a", border:"1px solid rgba(255,255,255,0.1)", borderRadius:20, padding:"40px 32px", width:"100%", maxWidth:360, textAlign:"center" }}>
        <div style={{ fontSize:36, marginBottom:16 }}>🔐</div>
        <h2 style={{ fontFamily:"Syne", fontSize:22, fontWeight:800, marginBottom:8 }}>Admin Panel</h2>
        <p style={{ fontSize:13, color:"rgba(255,255,255,0.4)", marginBottom:24 }}>Enter your admin password to continue</p>
        <input type="password" placeholder="Password" value={pass} onChange={e => setPass(e.target.value)} onKeyDown={e => e.key==="Enter" && (pass===ADMIN_PASS ? setAuthed(true) : alert("Wrong password!"))} style={{ marginBottom:16, textAlign:"center" }} />
        <button onClick={() => pass===ADMIN_PASS ? setAuthed(true) : alert("Wrong password!")} className="btn-primary" style={{ width:"100%", justifyContent:"center", animation:"none" }}>Login</button>
        <button onClick={onClose} style={{ marginTop:12, width:"100%", padding:"10px", background:"none", border:"1px solid rgba(255,255,255,0.1)", color:"rgba(255,255,255,0.5)", borderRadius:8, fontFamily:"DM Sans", cursor:"pointer", fontSize:13 }}>Cancel</button>
      </div>
    </div>
  );

  const saveAll = () => {
    saveInfo(infoEdit); setInfo(infoEdit);
    saveProjects(projects);
    setSaved(true); setTimeout(() => setSaved(false), 2000);
  };

  const deleteProj = (id) => setProjects(projects.filter(p => p.id !== id));

  const addProj = () => {
    if (!newProj.title) return;
    const p = { ...newProj, id: Date.now() };
    setProjects([...projects, p]);
    saveProjects([...projects, p]);
    setNewProj({ title:"", cat:"Web", year:"2025", desc:"", color:"#4DFFB4", icon:"🌐", link:"" });
  };

  const updateProj = () => {
    const updated = projects.map(p => p.id===editProj.id ? editProj : p);
    setProjects(updated); saveProjects(updated); setEditProj(null);
  };

  const tabs = ["info","projects","add"];
  const tabLabels = { info:"📋 Info", projects:"📁 Projects", add:"➕ Add Project" };

  return (
    <div style={{ position:"fixed", inset:0, zIndex:2000, background:"rgba(0,0,0,0.85)", backdropFilter:"blur(8px)", display:"flex", alignItems:"flex-start", justifyContent:"center", padding:"20px 16px", overflowY:"auto" }}>
      <div style={{ background:"#0d0d1a", border:"1px solid rgba(255,255,255,0.1)", borderRadius:20, width:"100%", maxWidth:760, marginTop:8 }}>
        {/* Header */}
        <div style={{ padding:"20px 24px", borderBottom:"1px solid rgba(255,255,255,0.08)", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <div>
            <h2 style={{ fontFamily:"Syne", fontSize:20, fontWeight:800 }}>⚙️ Admin Panel</h2>
            <p style={{ fontSize:12, color:"rgba(255,255,255,0.3)", marginTop:3 }}>Manage your portfolio content</p>
          </div>
          <div style={{ display:"flex", gap:10, alignItems:"center" }}>
            {saved && <span style={{ fontSize:13, color:"#4DFFB4", fontWeight:600 }}>✓ Saved!</span>}
            <button onClick={saveAll} className="btn-primary" style={{ padding:"9px 18px", fontSize:13, animation:"none" }}>Save All</button>
            <button onClick={onClose} style={{ padding:"9px 14px", background:"rgba(255,255,255,0.05)", border:"1px solid rgba(255,255,255,0.1)", color:"#fff", borderRadius:8, cursor:"pointer", fontFamily:"DM Sans", fontSize:13 }}>✕ Close</button>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:"flex", gap:0, borderBottom:"1px solid rgba(255,255,255,0.08)" }}>
          {tabs.map(t => (
            <button key={t} onClick={() => setTab(t)} style={{ flex:1, padding:"14px", background:"none", border:"none", borderBottom:tab===t?"2px solid #FF4D6D":"2px solid transparent", color:tab===t?"#FF4D6D":"rgba(255,255,255,0.4)", fontFamily:"DM Sans", fontSize:13, fontWeight:600, cursor:"pointer", transition:"all 0.2s" }}>{tabLabels[t]}</button>
          ))}
        </div>

        <div style={{ padding:"24px" }}>
          {/* INFO TAB */}
          {tab==="info" && (
            <div style={{ display:"grid", gap:14 }}>
              <h3 style={{ fontFamily:"Syne", fontSize:16, fontWeight:700, marginBottom:4 }}>Personal Information</h3>
              {[
                { l:"Full Name", k:"name" }, { l:"Tagline", k:"tagline" },
                { l:"University", k:"university" }, { l:"Location", k:"location" },
                { l:"Email", k:"email" }, { l:"LinkedIn URL", k:"linkedin" },
                { l:"GitHub URL", k:"github" },
              ].map(f => (
                <div key={f.k}>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>{f.l}</label>
                  <input value={infoEdit[f.k]||""} onChange={e => setInfoEdit({...infoEdit,[f.k]:e.target.value})} placeholder={f.l} />
                </div>
              ))}
              <div>
                <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Bio</label>
                <textarea rows={4} value={infoEdit.bio||""} onChange={e => setInfoEdit({...infoEdit,bio:e.target.value})} />
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:12 }}>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Years Exp</label>
                  <input type="number" value={infoEdit.yearsExp||0} onChange={e => setInfoEdit({...infoEdit,yearsExp:+e.target.value})} />
                </div>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Projects Count</label>
                  <input type="number" value={infoEdit.projectsCount||0} onChange={e => setInfoEdit({...infoEdit,projectsCount:+e.target.value})} />
                </div>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Available?</label>
                  <select value={infoEdit.available?"yes":"no"} onChange={e => setInfoEdit({...infoEdit,available:e.target.value==="yes"})}>
                    <option value="yes">✅ Yes</option>
                    <option value="no">❌ No</option>
                  </select>
                </div>
              </div>
            </div>
          )}

          {/* PROJECTS TAB */}
          {tab==="projects" && (
            <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
              <h3 style={{ fontFamily:"Syne", fontSize:16, fontWeight:700, marginBottom:4 }}>Manage Projects ({projects.length})</h3>
              {projects.map(p => (
                <div key={p.id} style={{ padding:"14px 16px", borderRadius:12, background:"rgba(255,255,255,0.03)", border:"1px solid rgba(255,255,255,0.08)", display:"flex", alignItems:"center", justifyContent:"space-between", gap:12, flexWrap:"wrap" }}>
                  {editProj?.id===p.id ? (
                    <div style={{ width:"100%", display:"grid", gap:10 }}>
                      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
                        <input value={editProj.title} onChange={e => setEditProj({...editProj,title:e.target.value})} placeholder="Title" />
                        <input value={editProj.link} onChange={e => setEditProj({...editProj,link:e.target.value})} placeholder="GitHub URL" />
                      </div>
                      <textarea rows={2} value={editProj.desc} onChange={e => setEditProj({...editProj,desc:e.target.value})} placeholder="Description" />
                      <div style={{ display:"flex", gap:10 }}>
                        <button onClick={updateProj} className="btn-primary" style={{ padding:"8px 16px", fontSize:12, animation:"none" }}>Save</button>
                        <button onClick={() => setEditProj(null)} style={{ padding:"8px 16px", background:"none", border:"1px solid rgba(255,255,255,0.15)", color:"#fff", borderRadius:7, cursor:"pointer", fontFamily:"DM Sans", fontSize:12 }}>Cancel</button>
                      </div>
                    </div>
                  ) : (
                    <>
                      <div style={{ display:"flex", alignItems:"center", gap:12, flex:1, minWidth:0 }}>
                        <span style={{ fontSize:24, flexShrink:0 }}>{p.icon}</span>
                        <div style={{ minWidth:0 }}>
                          <div style={{ fontFamily:"Syne", fontSize:14, fontWeight:700, color:"#fff" }}>{p.title}</div>
                          <div style={{ fontSize:11, color:"rgba(255,255,255,0.35)", marginTop:2 }}>{p.cat} • {p.year}</div>
                          <div style={{ fontSize:11, color:"#A78BFA", marginTop:2, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{p.link}</div>
                        </div>
                      </div>
                      <div style={{ display:"flex", gap:8, flexShrink:0 }}>
                        <button onClick={() => setEditProj({...p})} style={{ padding:"7px 13px", background:"rgba(255,255,255,0.05)", border:"1px solid rgba(255,255,255,0.1)", color:"#fff", borderRadius:7, cursor:"pointer", fontFamily:"DM Sans", fontSize:12 }}>Edit</button>
                        <button onClick={() => deleteProj(p.id)} style={{ padding:"7px 13px", background:"rgba(255,77,109,0.1)", border:"1px solid rgba(255,77,109,0.3)", color:"#FF4D6D", borderRadius:7, cursor:"pointer", fontFamily:"DM Sans", fontSize:12 }}>Delete</button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
          )}

          {/* ADD PROJECT TAB */}
          {tab==="add" && (
            <div style={{ display:"grid", gap:14 }}>
              <h3 style={{ fontFamily:"Syne", fontSize:16, fontWeight:700, marginBottom:4 }}>Add New Project</h3>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Project Title *</label>
                  <input value={newProj.title} onChange={e => setNewProj({...newProj,title:e.target.value})} placeholder="My Awesome Project" />
                </div>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Category</label>
                  <select value={newProj.cat} onChange={e => setNewProj({...newProj,cat:e.target.value})}>
                    {["Web","Mobile","AI","Systems"].map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Year</label>
                  <input value={newProj.year} onChange={e => setNewProj({...newProj,year:e.target.value})} placeholder="2025" />
                </div>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Icon (emoji)</label>
                  <input value={newProj.icon} onChange={e => setNewProj({...newProj,icon:e.target.value})} placeholder="🚀" />
                </div>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Color (hex)</label>
                  <input value={newProj.color} onChange={e => setNewProj({...newProj,color:e.target.value})} placeholder="#4DFFB4" />
                </div>
                <div>
                  <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>GitHub/Live Link *</label>
                  <input value={newProj.link} onChange={e => setNewProj({...newProj,link:e.target.value})} placeholder="https://github.com/..." />
                </div>
              </div>
              <div>
                <label style={{ fontSize:11, color:"rgba(255,255,255,0.4)", letterSpacing:"0.1em", textTransform:"uppercase", display:"block", marginBottom:6 }}>Description</label>
                <textarea rows={3} value={newProj.desc} onChange={e => setNewProj({...newProj,desc:e.target.value})} placeholder="What does this project do?" />
              </div>
              {/* Preview */}
              {newProj.title && (
                <div style={{ padding:"14px 16px", borderRadius:12, background:`${newProj.color}12`, border:`1px solid ${newProj.color}30` }}>
                  <div style={{ fontSize:11, color:"rgba(255,255,255,0.4)", marginBottom:6 }}>PREVIEW</div>
                  <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                    <span style={{ fontSize:28 }}>{newProj.icon}</span>
                    <div>
                      <div style={{ fontFamily:"Syne", fontSize:15, fontWeight:700, color:"#fff" }}>{newProj.title}</div>
                      <div style={{ fontSize:11, color:newProj.color }}>{newProj.cat} • {newProj.year}</div>
                    </div>
                  </div>
                </div>
              )}
              <button onClick={addProj} className="btn-primary" style={{ alignSelf:"flex-start", animation:"none" }}>➕ Add Project</button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* ─── APP ─────────────────────────────────────────────────────────────── */
export default function App() {
  const [active, setActive] = useState("hero");
  const [showAdmin, setShowAdmin] = useState(false);
  const [showTop, setShowTop] = useState(false);
  const { projects: initP, info: initI } = loadData();
  const [projects, setProjects] = useState(initP);
  const [info, setInfo] = useState(initI);

  useEffect(() => {
    const sections = ["hero","about","projects","skills","contact"];
    const obs = new IntersectionObserver(entries => {
      entries.forEach(e => { if (e.isIntersecting) setActive(e.target.id); });
    }, { threshold: 0.3 });
    sections.forEach(id => { const el = document.getElementById(id); if (el) obs.observe(el); });
    return () => obs.disconnect();
  }, []);

  // Scroll-reveal: fade-in-up on sections
  useEffect(() => {
    const revObs = new IntersectionObserver(entries => {
      entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add("revealed"); revObs.unobserve(e.target); } });
    }, { threshold: 0.1 });
    document.querySelectorAll(".section").forEach(el => revObs.observe(el));
    return () => revObs.disconnect();
  }, []);

  // Scroll-to-top button visibility
  useEffect(() => {
    const fn = () => setShowTop(window.scrollY > 300);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);

  return (
    <>
      <style>{CSS}</style>
      <Nav active={active} onAdmin={() => setShowAdmin(true)} />
      <main>
        <Hero info={info} />
        <Marquee />
        <About info={info} />
        <Projects projects={projects} />
        <Skills />
        <Contact info={info} />
      </main>
      <Footer info={info} />
      {showAdmin && (
        <AdminPanel
          onClose={() => setShowAdmin(false)}
          projects={projects} setProjects={setProjects}
          info={info} setInfo={setInfo}
        />
      )}
      {showTop && (
        <button
          onClick={() => window.scrollTo({ top:0, behavior:"smooth" })}
          style={{
            position:"fixed", bottom:32, right:32, zIndex:999,
            width:46, height:46, borderRadius:"50%",
            background:"linear-gradient(135deg,#FF4D6D,#A78BFA)",
            border:"none", color:"#fff", fontSize:20, cursor:"pointer",
            boxShadow:"0 4px 20px rgba(255,77,109,0.4)",
            display:"flex", alignItems:"center", justifyContent:"center",
            transition:"transform 0.2s, opacity 0.3s",
            animation:"fadeInUp 0.3s ease"
          }}
          onMouseEnter={e => e.currentTarget.style.transform="scale(1.15)"}
          onMouseLeave={e => e.currentTarget.style.transform="scale(1)"}
          title="Back to top"
        >↑</button>
      )}
    </>
  );
}